UPDATE products SET name = 'Bladderwrack Powder', blurb = 'Our bladderwrack powder is ground from Fucus vesiculosus, a type of brown seaweed harvested along the cool Atlantic coastal waters. Bladderwrack got its name from its thalli, or “bladders”, that fill with air in order to keep the seaweed afloat.', description = 'Our bladderwrack powder is ground from Fucus vesiculosus, a type of brown seaweed harvested along the cool Atlantic coastal waters. Bladderwrack got its name from its thalli, or “bladders”, that fill with air in order to keep the seaweed afloat. This particular seaweed powder has a high iodine content and can be incorporated into culinary dishes and spice blends. Bladderwrack powder can even be used in body care recipes. Bladderwrack is also called dyer’s focus, red focus, and rockwrack. It is a member of the Fucaceae family. Precautions
